import{_ as d,I as l,o as c,c as h,a6 as r,J as a,w as i,j as e,a as o,aA as u}from"./chunks/framework.zaV2WUSU.js";const v=JSON.parse('{"title":"Game Cheats with EdiZon","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/edizon.md","filePath":"homebrew/edizon.md"}'),m={name:"homebrew/edizon.md"};function f(p,t,b,g,_,y){const n=l("Tab"),s=l("Tabs");return c(),h("div",null,[t[2]||(t[2]=r('<h1 id="game-cheats-with-edizon" tabindex="-1">Game Cheats with EdiZon <a class="header-anchor" href="#game-cheats-with-edizon" aria-label="Permalink to “Game Cheats with EdiZon”">​</a></h1><p>For cheats management, <a href="https://github.com/WerWolv/EdiZon" target="_blank" rel="noreferrer">EdiZon</a> and/or <a href="https://github.com/tomvita/EdiZon-SE" target="_blank" rel="noreferrer">EdiZon-SE</a> (up to date and offers more features) are recommended. They offer support for Atmosphère&#39;s cheat engine, providing an easy way to download new cheats, as well as toggle them on or off.</p><h2 id="section-i-requirements" tabindex="-1">Section I - Requirements <a class="header-anchor" href="#section-i-requirements" aria-label="Permalink to “Section I - Requirements”">​</a></h2><ul><li>An archive manager like <a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></li><li>The latest release of <a href="https://github.com/WerWolv/EdiZon/releases" target="_blank" rel="noreferrer">EdiZon</a> (the <code>EdiZon.nro</code> file) or <a href="https://github.com/tomvita/EdiZon-SE/releases" target="_blank" rel="noreferrer">EdiZon-SE</a> (the <code>EdiZon.zip</code> file)</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>EdiZon overlay</strong></p><p>EdiZon also offers a Tesla-Menu overlay, however, the official EdiZon overlay is no longer maintained and will result in Atmosphère crashing when trying to use the EdiZon overlay on firmware version 16.0.0+.</p><p>The maintained overlay can be found on the <a href="https://github.com/proferabg/EdiZon-Overlay/releases" target="_blank" rel="noreferrer">EdiZon Overlay GitHub</a> repository.</p></div><h2 id="section-ii-installation" tabindex="-1">Section II - Installation <a class="header-anchor" href="#section-ii-installation" aria-label="Permalink to “Section II - Installation”">​</a></h2>',6)),a(s,{tabs:""},{default:i(()=>[a(n,{name:"EdiZon",default:"true"},{default:i(()=>[...t[0]||(t[0]=[e("ol",null,[e("li",null,[o("Boot into hekate and go to "),e("code",null,"Tools"),o(" > "),e("code",null,"USB Tools"),o(" > "),e("code",null,"SD Card"),o(", then plug your Switch into your PC via USB.")]),e("li",null,"Your microSD card should now be accessible on your PC, open it."),e("li",null,[o("Put the "),e("code",null,"EdiZon.nro"),o(" in "),e("code",null,"sd:/switch"),o(".")]),e("li",null,"Boot into CFW.")],-1)])]),_:1}),a(n,{name:"EdiZon-SE"},{default:i(()=>[...t[1]||(t[1]=[e("ol",null,[e("li",null,[o("Boot into hekate and go to "),e("code",null,"Tools"),o(" > "),e("code",null,"USB Tools"),o(" > "),e("code",null,"SD Card"),o(", then plug your Switch into your PC via USB.")]),e("li",null,"Your microSD card should now be accessible on your PC, open it."),e("li",null,[o("Extract the "),e("code",null,".zip"),o(" file to a location on your computer. "),e("ul",null,[e("li",null,[o("If your archive manager allows for it, you can also simply open the "),e("code",null,".zip"),o(" file directly.")])])]),e("li",null,[o("Copy the "),e("em",null,"contents"),o(" of the (extracted) "),e("code",null,".zip"),o(" file to the root of your microSD card. "),e("ul",null,[e("li",null,[e("strong",null,"Optional:"),o(" You can verify if you've installed EdiZon-SE correctly, you should have a folder called "),e("code",null,"054e4f4558454000"),o(" (EdiZon-SE) in "),e("code",null,"sd:/atmosphere/contents"),o(" and an "),e("code",null,"EdiZon.nro"),o(" file in "),e("code",null,"sd:/switch/EdiZon"),o(".")])])]),e("li",null,"Boot into CFW.")],-1)])]),_:1})]),_:1}),t[3]||(t[3]=r('<h2 id="section-iii-usage" tabindex="-1">Section III - Usage <a class="header-anchor" href="#section-iii-usage" aria-label="Permalink to “Section III - Usage”">​</a></h2><p>Atmosphère looks for cheats to load in the <code>contents</code> sub-folder of the <code>atmosphere</code> folder. The template it looks for is <code>sd:/atmosphere/contents/&lt;title_id&gt;/cheats/&lt;build_id&gt;.txt</code>. You need to create the <code>&lt;title_id&gt;</code> folder and sub-folders manually:</p><ul><li><code>title_id</code> being the title or program of a game. This is game specific and can be found on EdiZon&#39;s cheat menu (TID and BID, see the bottom of this page for a sample), <a href="https://switchbrew.org/wiki/Title_list/Games" target="_blank" rel="noreferrer">switchbrew</a> and <a href="https://nswdb.com/" target="_blank" rel="noreferrer">nswdb</a>. <ul><li><strong>Note:</strong> Title ID means the same thing as Program ID.</li></ul></li><li><code>build_id</code> being the version of a game. This is game specific and can be found on EdiZon&#39;s cheat menu (BID, see the bottom of this page for a sample) Cheats can be version specific so make sure the cheats you are using are compatible with your game version.</li></ul><p><strong>Note:</strong> On Atmosphère 0.9.4 and below <code>contents</code> is called <code>titles</code>.</p><p>Once the title is launched while in Atmosphère, your cheats should be applied.</p><h3 id="preventing-cheats-from-being-enabled-by-default" tabindex="-1">Preventing cheats from being enabled by default <a class="header-anchor" href="#preventing-cheats-from-being-enabled-by-default" aria-label="Permalink to “Preventing cheats from being enabled by default”">​</a></h3><p>To prevent cheats from being enabled by default, you can change your Atmosphère configuration by following the steps below.</p><ol><li>Copy <code>system_settings.ini</code> from <code>sd:/atmosphere/config_templates</code> to <code>sd:/atmosphere/config</code> if it&#39;s not already there.</li><li>Open the <code>system_settings.ini</code> file with a text editor and edit the line <code>; dmnt_cheats_enabled_by_default = u8!0x1</code> to <code>dmnt_cheats_enabled_by_default = u8!0x0</code>. <ul><li>Make sure you remove the space and the semicolon &quot;<code>;</code>&quot; in front of <code>dmnt_cheats_enabled_by_default</code>.</li></ul></li></ol><p>By default, holding the L button while launching a game will disable any game modification.</p><p>Here the Title ID of the game (TID) is <code>0100646009FBE000</code> and the Build ID of the game (BID) is <code>0B9A75586BC1A6C6</code>. Cheats are loaded from <code>sd:/atmosphere/contents/0100646009FBE000/cheats/0B9A75586BC1A6C6.txt</code> in this example.</p><p><img src="'+u+'" alt="ExampleGameCheat"></p><h2 id="section-iv-additional-information" tabindex="-1">Section IV - Additional Information <a class="header-anchor" href="#section-iv-additional-information" aria-label="Permalink to “Section IV - Additional Information”">​</a></h2><p>For more in-depth details about Atmosphère&#39;s cheat engine, you can refer to <a href="https://github.com/Atmosphere-NX/Atmosphere/blob/master/docs/features/cheats.md" target="_blank" rel="noreferrer">this page</a>.</p><h2 id="section-v-troubleshooting" tabindex="-1">Section V - Troubleshooting <a class="header-anchor" href="#section-v-troubleshooting" aria-label="Permalink to “Section V - Troubleshooting”">​</a></h2><h3 id="edizon-isn-t-showing-up-when-i-open-the-homebrew-menu" tabindex="-1">EdiZon isn&#39;t showing up when I open the Homebrew menu! <a class="header-anchor" href="#edizon-isn-t-showing-up-when-i-open-the-homebrew-menu" aria-label="Permalink to “EdiZon isn&#39;t showing up when I open the Homebrew menu!”">​</a></h3><p>Assuming you&#39;ve followed the installation instructions successfully, this is probably due to the archive bit being set on one or more folders/files on your microSD card. This is usually the result of copying files to a microSD card via a Mac. If you are experiencing this issue, try running the archive bit fixer utility via hekate for all files.</p><p>This can be done by booting into hekate and going to <code>Tools</code> &gt; <code>Arch bit • RCM Touch • Pkg1/2</code> &gt; <code>Fix Archive Bit</code>.</p>',17))])}const E=d(m,[["render",f]]);export{v as __pageData,E as default};
